            case TypeRank::DOUBLE:
            case TypeRank::INT64: {
                return lexer::Number(~static_cast<uint64_t>(ExtractFromLiteral<int64_t>(node)));
            }
            case TypeRank::FLOAT:
            case TypeRank::INT32:
            case TypeRank::INT16:
            case TypeRank::INT8: {
                return lexer::Number(~static_cast<uint32_t>(ExtractFromLiteral<int32_t>(node)));
            }
            default: {
                ES2PANDA_UNREACHABLE();
            }
