    {
        ES2PANDA_ASSERT(inputs_.size() == 1);
        if (unary->OperatorType() == lexer::TokenType::PUNCTUATOR_EXCLAMATION_MARK) {
            return CreateBooleanLiteral(!TestLiteral(inputs_[0]));
