        ES2PANDA_ASSERT(containingClass->AsClassDefinition()->TsType() != nullptr &&
                        containingClass->AsClassDefinition()->TsType()->IsETSObjectType());
        return containingClass->AsClassDefinition()->TsType()->AsETSObjectType();
    }

    checker->LogError(diagnostic::CTOR_REF_INVALID_CTX_GLOBAL, {msg}, node->Start());
    return checker->GlobalTypeError();
}

static bool IsRootLevelConstructorCall(const ir::CallExpression *callExpr, const ir::BlockStatement *blockStmt)
{
    if (callExpr->Parent() == nullptr || !callExpr->Parent()->IsExpressionStatement()) {
        return false;
    }

    auto *exprStmt = callExpr->Parent()->AsExpressionStatement();
    if (exprStmt->Parent() == nullptr || !exprStmt->Parent()->IsBlockStatement()) {
        return false;
    }

    return exprStmt->Parent()->AsBlockStatement() == blockStmt;
}

static ir::Statement *FindContainingStatement(const ir::Expression *node, const ir::BlockStatement *blockStmt)
{
    const ir::AstNode *current = node;
    while (current != nullptr && current->Parent() != blockStmt) {
        current = current->Parent();
    }
    return current != nullptr ? const_cast<ir::AstNode *>(current)->AsStatement() : nullptr;
}

