    } else if (typeRel->IsSupertypeOf(checker->GlobalShortBuiltinType(), paramType)) {
        number.TryNarrowTo<int16_t>();
    } else if (typeRel->IsSupertypeOf(checker->GlobalByteBuiltinType(), paramType)) {
        number.TryNarrowTo<int8_t>();
