/*---
desc: >-
    Trace-oriented runtime coverage for distinct constant-expression lowering branches:
    boolean bitwise folding, string additive folding, floating exceptional arithmetic,
    negative-zero exponentiation, undefined short-circuit normalization, and extended
    boolean truthiness for string and char literals.
---*/

function main() {
    let suite = new arktest.ArkTestsuite("Constant expression lowering trace paths")

    suite.addTest("boolean bitwise branch", () => {
        const value = true ^ false
        arktest.assertEQ(value, true)
    })

    suite.addTest("string additive branch", () => {
        const value = "x" + 1
        arktest.assertEQ(value, "x1")
    })

    suite.addTest("floating exceptional arithmetic branch", () => {
        const divZero = 1.0 / 0.0
        const modZero = 1.0 % 0.0
        arktest.assertTrue(divZero > 1.0e300)
        arktest.assertTrue(modZero != modZero)
    })

    suite.addTest("negative zero exponentiation branch", () => {
        const value = (-0.0) ** (-1)
        arktest.assertTrue(value < -1.0e300)
    })

    suite.addTest("undefined short-circuit normalization branch", () => {
        const undef = undefined
        const fallback = undef || 5
        const stuck = undef && 5
        arktest.assertEQ(fallback, 5)
        arktest.assertEQ(stuck, undefined)
    })

    suite.addTest("extended boolean truthiness for string and char", () => {
        const emptyString = "" ? 1 : 2
        const nonEmptyString = "ok" ? 1 : 2
        const zeroChar = c'\u0000' ? 1 : 2
        const nonZeroChar = c'a' ? 1 : 2

        arktest.assertEQ(emptyString, 2)
        arktest.assertEQ(nonEmptyString, 1)
        arktest.assertEQ(zeroChar, 2)
        arktest.assertEQ(nonZeroChar, 1)
    })

    return suite.run()
}

