/*---
desc: >-
    Trace coverage for the integral division-by-zero diagnostic emitted during constant
    expression folding.
tags: [negative, compile-only]
expected_out: "Syntax error ESY0273: Division by zero is not allowed in integer arithmetic."
---*/

@interface DivZeroAnn {
    value: int = 1 / 0
}

@DivZeroAnn()
class DivZeroHolder {}

edits.oldText:
suite.addTest("floating exceptional arithmetic branch", () => {
    const divZero = 1.0 / 0.0
    const modZero = 1.0 % 0.0
    arktest.assertTrue(divZero > 1.0e300)
    arktest.assertTrue(modZero != modZero)
})

edits.newText:
suite.addTest("floating exceptional arithmetic branch", () => {
    const divZero = 1.0 / 0.0
    const modZero = 1.0 % 0.0
    arktest.assertTrue(divZero > 1.0e300)
    arktest.assertTrue(Number.isNaN(modZero))
