/*---
desc: Switch statement with interpolated string.
---*/

const foo: string = 'AbyrvalG'
let result = 'miss'

function sint() {
    switch(`abc${foo}cba`) {
        case 'abc': break
        case '123': break
        case `abc${foo}cba`: result = 'hit'
    }
}

function main() {
    result = 'miss'
    sint()
    arktest.assertEQ('hit', result)
}

