desc: annotation compile-time errors 
tags: [compile-only, negative]
---*/

let l: number = 100

const bsa: string[] = ['1', '2', '3']
const c: number = 200 + l

@interface SomeAnnotation {
   field1: number {{ case.value }}
   field2: string
}

@interface ArrayFieldAnnotation {
   field: string[]
}

{{ case.decl }}

