cases:
  - decl: |-
      @SomeAnnotation({field2: "Some string"})
      @SomeAnnotation({field2: "Some string"})
      class SomeClass {}
    value: |-
       = 100
  - decl: |-
      @SomeAnnotation({field2: "Some_string"})
      class SomeClass {}
  - decl: |-
      @SomeAnnotation({field1: l + 100, field2: "Some_string"})
      class SomeClass {}
  - decl: |-
      @SomeAnnotation({field1: c + 100, field2: "Some_string"})
      class SomeClass {}
  - decl: |-
      function foo() @SomeAnnotation({field2: "Some_string"}) {} // Wrong target for annotation
  - decl: |-
      @SomeAnnotation({field1: c, field2: "Some_string"})
      class SomeClass {}
  - value: |-
       = l + 100
  - value: |-
       = c + 100
  - value: |-
       = c
  - decl: |-
      @ArrayFieldAnnotation({field: [...bsa]})
      class SomeClass {}
    value: |-
      = 100

